(function () {const MPP_FONT_FAMILIES = {Montserrat: "Montserrat:wght@500;700;800;900","Bebas Neue": "Bebas+Neue",Oswald: "Oswald:wght@500;700;800;900","Playfair Display": "Playfair+Display:wght@500;700;800;900",};const loadedFamilies = new Set(["Montserrat"]);function extractPrimaryFamily(fontStack) {if (!fontStack) return "";const match = String(fontStack).match(/['"]?([^'",]+)['"]?\s*,/);return (match ? match[1] : fontStack.split(",")[0] || "").trim();}function ensureMppFontFamily(familyName) {const family = String(familyName || "").trim();if (!family || loadedFamilies.has(family)) return;const spec = MPP_FONT_FAMILIES[family];if (!spec) return;loadedFamilies.add(family);const link = document.createElement("link");link.rel = "stylesheet";link.href = `https://fonts.googleapis.com/css2?family=${spec}&display=swap`;document.head.appendChild(link);}function ensureMppFontsFromStacks(...stacks) {stacks.forEach((stack) => {const family = extractPrimaryFamily(stack);if (family) ensureMppFontFamily(family);});}window.ensureMppFontFamily = ensureMppFontFamily;window.ensureMppFontsFromStacks = ensureMppFontsFromStacks;})();
